import { useContextSelector } from 'use-context-selector';
import { RcTriggerPopperSidecar } from '../../shared/components/popper-sidecar/RcTriggerPopperSidecar';
import { ConfigContext } from '../ConfigContext';

export function usePopperSidecar() {
  return useContextSelector(ConfigContext, o => o.PopperSidecar) ?? RcTriggerPopperSidecar;
}
